html: <!-- solution code -->
<div class="mx-4 mt-4">
  <ul id="virtual-list" class="virtual-list overflow-y-auto h-96" role="list" aria-label="Virtual List">
    <template id="list-item-template">
css: .virtual-list {
  @apply overflow-y-auto max-h-96 w-full;
}

.list-item {
  @apply p-2 bg-white mb-2;
}

.virtual-list [role="listitem"] {
  @apply block;
}

.virtual-list [role="listitem"]:focus {
  @apply ring-2 ring-orange-500;
}

.virtual-list [role="listitem"]:active {
  @apply outline-none;
}

javascript: // solution code
